import {
  select, scaleBand,
  axisBottom,
  format,
  scaleLinear,
  max,
  axisLeft,
  scaleOrdinal,
} from "d3"

export default class Bar extends HTMLElement {
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    shadowRoot.innerHTML = `
      <style>
        :host {
          display: flex;
        }
        .root {
          font-family: var(--font-family);
          font-size: 18px;
          display: inline-block;
          height: 100%;
          width: 100%;
          text-align: left;
        } 
        svg {
          width: 100%;
          height: 100%;
          position: relative;
        }
        .bar {
          fill: #0072BC;
        }
        text {
          font-family: lato;
          font-size: 10px;
          fill: #333333;
        }
        .grid path {
          stroke-width: 0;
          stroke: #333333;
        }
        .grid .tick line {
          stroke: #333333;
          stroke-width: 0.3px;
          stroke-opacity: 0.3;
        }
        text.chart-title {
          font-size: 14px;
          fill:#222222
        }
        text.chart-label {
          font-size: 10px;
          font-weight: 400;
          fill: #999999;
        }
        text.chart-source {
          font-size: 8px;
          fill: #999999;
        }
        text.copyright {
          font-size: 8px;
          fill: #999999;
        }
        .tooltip {
          background-color: #ffffff;
          font-family: lato;
          font-size: 11px;
          padding: 4px;
          color: #666666;
          border: none;
          box-shadow: 0px 0px 3px 0px #E6E6E6;
        }
        .legend{
          font-size: 10px;
          fill: var(--text-tertiary);
        }
        .x-scale text, .y-scale text {
          fill: var(--text-tertiary);
        }
      </style>
      <div class="root"></div>
    `
  }

  connectedCallback() {
    this.classList.add("hydrated")
    this.render()
  }

  render = () => {
    // set the dimensions and margins of the graph
    const margin = { top: 40, right: 20, bottom: 50, left: 40 };
    const svg_width = 550
    const svg_height = 450
    const width = 450 - margin.left - margin.right;
    const height = 350 - margin.top - margin.bottom;

    // append the svg object to the body of the page
    const root = this.shadowRoot.querySelector(".root")
    const svg = select(root)
      .append("svg")
      .attr("width", "100%")
      .attr("height", "100%")
      .attr("viewBox", `0 0 ${svg_width} ${svg_height}`)
      .attr("preserveAspectRatio", "xMinYMin")
      .append("g")
      .attr("transform", `translate(${margin.left}, ${margin.top})`);

    //  Data
    const data = [
      {
        "month": 1,
        "interest": 900,
        "principle": 500
      },
      {
        "month": 2,
        "interest": 900,
        "principle": 200
      },
      {
        "month": 3,
        "interest": 900,
        "principle": 300
      },
      {
        "month": 4,
        "interest": 900,
        "principle": 300
      },
      {
        "month": 5,
        "interest": 900,
        "principle": 300
      },
      {
        "month": 6,
        "interest": 900,
        "principle": 300
      },
      {
        "month": 7,
        "interest": 900,
        "principle": 300
      },
      {
        "month": 8,
        "interest": 900,
        "principle": 300
      },
      {
        "month": 9,
        "interest": 900,
        "principle": 300
      },
      {
        "month": 10,
        "interest": 900,
        "principle": 300
      },
      {
        "month": 11,
        "interest": 900,
        "principle": 300
      },
      {
        "month": 12,
        "interest": 900,
        "principle": 300
      }
    ]

    // data wrangling
    const dataList = data.map(d => {
      return [
        d.month,
        [
          ["principle", d.principle],
          ["interest", d.interest]
        ]
      ]
    })

    const monthKeys = Array.from(dataList).map(d => d[0])
    const unitKey = Array.from(Array.from(dataList)[0][1]).map(d => d[0])

    // X scale and Axis
    const xScale = scaleBand()
      .domain(monthKeys)
      .range([0, width])
      .padding(.2);
    svg
      .append('g')
      .attr("class", "x-scale")
      .attr("transform", `translate(0,${height})`)
      .call(axisBottom(xScale).tickSize(0).tickPadding(8));

    // Y scale and Axis
    const formater = format(".1s")
    const yScale = scaleLinear()
      .domain([0, max(data.map(d => d.principle > d.interest ? d.principle : d.interest))])
      .range([height, 0]);
    svg
      .append('g')
      .attr("class", "y-scale")
      .call(axisLeft(yScale).ticks(4).tickSize(0).tickPadding(12).tickFormat(formater))
      .call(d => d.select(".domain").remove());

    // set subgroup sacle
    const xSubgroups = scaleBand()
      .domain(unitKey)
      .range([0, xScale.bandwidth()])
      .padding([0.05])

    // color palette
    const color = scaleOrdinal()
      .domain(unitKey)
      .range(['#18375F', '#0072BC'])

    // set horizontal grid line
    const GridLine = () => axisLeft().scale(yScale);
    svg
      .append("g")
      .attr("class", "grid")
      .call(GridLine()
        .ticks(3)
        .tickSize(-width, 0, 0)
        .tickFormat("")
      );

    // create a tooltip
    const tooltip = select("body")
      .append("div")
      .attr("id", "chart")
      .attr("class", "tooltip");

    // tooltip events
    const mouseover = function (d) {
      tooltip
        .style("opacity", .8)
      select(this)
        .style("opacity", .5)
    }
    const mousemove = function (event, d) {
      const formater = format(",")
      tooltip
        .html(formater(d[1]))
        .style("position", "absolute")
        .style("top", event.y - 10 + "px")
        .style("left", event.x + 10 + "px");
    }
    const mouseleave = function (d) {
      tooltip
        .style("opacity", 0)
      select(this)
        .style("opacity", 1)
    }

    // create bars
    svg.append("g")
      .selectAll("g")
      .data(dataList)
      .join("g")
      .attr("transform", d => "translate(" + xScale(d[0]) + ", 0)")
      .selectAll("rect")
      .data(d => { return d[1] })
      .join("rect")
      .attr("x", d => xSubgroups(d[0]))
      .attr("y", d => yScale(d[1]))
      .attr("width", xSubgroups.bandwidth())
      .attr("height", d => height - yScale(d[1]))
      .attr("fill", d => color(d[0]))
      .on("mouseover", mouseover)
      .on("mousemove", mousemove)
      .on("mouseleave", mouseleave);

    // set title
    svg
      .append("text")
      .attr("class", "chart-title")
      .attr("x", -(margin.left) * 0.6)
      .attr("y", -(margin.top) / 1.5)
      .attr("text-anchor", "start")
      .text("")

    svg
      .append("rect")
      .attr("x", -(margin.left) * 0.6)
      .attr("y", height + margin.bottom)
      .attr("width", 13)
      .attr("height", 13)
      .style("fill", "#18375F");
    svg
      .append("text")
      .attr("class", "legend")
      .attr("x", -(margin.left) * 0.6 + 20)
      .attr("y", height + margin.bottom + 10)
      .text("Principle")
    svg
      .append("rect")
      .attr("x", 60)
      .attr("y", height + margin.bottom)
      .attr("width", 13)
      .attr("height", 13)
      .style("fill", "#0072BC")
    svg
      .append("text")
      .attr("class", "legend")
      .attr("x", 80)
      .attr("y", height + margin.bottom + 10)
      .text("Interest")
  }
}
